// Webhook с multipart складывает все файлы в одно item.binary с ключами
// data, data_0, data_1, ... Для последующего Spreadsheet File нужно, чтобы
// каждый файл был отдельным item с одним фиксированным binary-ключом «data».
// Заодно проставляем fileIndex/fileName в json, чтобы можно было
// различать происхождение строк после чтения.

const input = $input.first();
const binary = input.binary || {};
const keys = Object.keys(binary);

if (keys.length === 0) {
  throw new Error('Не загружено ни одного файла.');
}

const items = [];
let fileIndex = 0;
for (const key of keys) {
  const meta = binary[key] || {};
  const fileName = meta.fileName || ('file-' + fileIndex + '.xlsx');
  const lower = fileName.toLowerCase();
  if (!(lower.endsWith('.xlsx') || lower.endsWith('.xlsm'))) {
    throw new Error('Файл «' + fileName + '» имеет неподдерживаемое расширение. Принимаются только .xlsx и .xlsm.');
  }
  items.push({
    json: { fileIndex: fileIndex, fileName: fileName },
    binary: { data: meta }
  });
  fileIndex++;
}

return items;

// На входе — items от Spreadsheet File. Каждый item — одна строка xlsx,
// json содержит поля по заголовкам файла. pairedItem.item ссылается на
// исходный «файловый» item из ноды «Разбить на items», поэтому по нему
// можно определить, из какого файла строка.
//
// Логика слияния повторяет ту, что в Python-сервисе для Word:
//   1) Нормализуем заголовки (без пробелов, точек, регистра).
//   2) Объединяем порядок столбцов: первые столбцы первого файла → лишние
//      из второго → и т.д. (стабильно для пользователя).
//   3) Отображаемое имя столбца — первое встреченное.
//   4) Для каждой строки строим новую строку в едином порядке столбцов.
//      Если в исходной таблице столбца не было — пусто.

function extractFileIndex(item) {
  if (!item.pairedItem) return 0;
  if (typeof item.pairedItem === 'number') return item.pairedItem;
  if (Array.isArray(item.pairedItem)) return item.pairedItem[0] && item.pairedItem[0].item != null ? item.pairedItem[0].item : 0;
  if (item.pairedItem.item != null) return item.pairedItem.item;
  return 0;
}

function normalize(h) {
  if (h == null) return '';
  return String(h).trim().toLowerCase().replace(/[\s._\-(){}\[\]\\/:;,!?'\"]+/g, '');
}

const items = $input.all();
if (items.length === 0) {
  throw new Error('После чтения файлов не осталось ни одной строки данных.');
}

// Группируем строки по индексу исходного файла
const byFile = new Map();
for (const item of items) {
  const idx = extractFileIndex(item);
  if (!byFile.has(idx)) byFile.set(idx, []);
  byFile.get(idx).push(item.json || {});
}

// 1) Порядок столбцов в итоге + 2) каноническое отображаемое имя
const columnOrder = [];
const canonical = {};
for (const rows of byFile.values()) {
  if (rows.length === 0) continue;
  for (const k of Object.keys(rows[0])) {
    const norm = normalize(k);
    if (!norm) continue;
    if (!(norm in canonical)) {
      canonical[norm] = k;
      columnOrder.push(norm);
    }
  }
}

if (columnOrder.length === 0) {
  throw new Error('Во всех файлах заголовки пустые — нечего объединять.');
}

// 3) Собираем итоговые строки
const mergedRows = [];
for (const rows of byFile.values()) {
  if (rows.length === 0) continue;
  // Для этого файла: норм.ключ → оригинальный ключ
  const localMap = {};
  for (const k of Object.keys(rows[0])) {
    const norm = normalize(k);
    if (norm && !(norm in localMap)) localMap[norm] = k;
  }
  for (const row of rows) {
    const newRow = {};
    for (const norm of columnOrder) {
      const displayName = canonical[norm];
      const srcKey = localMap[norm];
      const v = srcKey != null ? row[srcKey] : null;
      // Числа Excel — оставляем как есть, без округления; null/undefined → пусто
      newRow[displayName] = v == null ? '' : v;
    }
    mergedRows.push(newRow);
  }
}

if (mergedRows.length === 0) {
  throw new Error('Во всех файлах нет данных кроме заголовков.');
}

return mergedRows.map(r => ({ json: r }));
